// CodegenServiceServer is the server API for CodegenService service.
// All implementations must embed UnimplementedCodegenServiceServer
// for forward compatibility.
//
// CodegenService is the storage-domain codegen surface: takes
// a project's full `.proto` set (so cross-file imports resolve)
// + the project's `service_id` and returns the generated
// Storage-layer Go handler files. Per-file dialect / Go
// package / proto import path are derived server-side from
// each file's annotations (see [GenerateRequest] doc).
//
// Deployment shape mirrors migrator's: storage/ defines the
// service + a hand-written server, console/ wraps it on the
// hosted gRPC endpoint, w17ctl is the developer-side CLI client.
//
// What's generated today: Storage-layer Go handler files +
// per-language pb / gRPC stubs (driven by the request's
// `stub_targets`; backed by an internal `bufbuild/buf` docker
// invocation per `lib/bufrun`). Per conventions-global/grpc.md
// the wandering-compiler does NOT generate Service / Facade
// layers — those are user-written against the generated
// stubs.
//
// Future scope (separate tasks; same RPC surface, fields added
// to the response):
//   - Gateway-domain code (REST/MCP proxy + event emit) when
//     that domain's generator lands.
//
// Not supported in M1:
//   - Multi-op gRPC methods (one Query + one Mutation per
//     method). The underlying generator returns
//     FailedPrecondition for those.
type CodegenServiceServer interface {
	// Generate compiles the input project's .proto files into
	// Storage-layer Go handler files. Input includes every
	// .proto in the project so cross-file imports resolve;
	// server walks each file's services and aggregates the
	// result.
	//
	// Returns gRPC INVALID_ARGUMENT for malformed input,
	// FAILED_PRECONDITION for unsupported shapes (e.g. multi-op
	// methods), INTERNAL for unexpected pipeline failures.
	// OK = success; the response carries the generated files.
	Generate(context.Context, *GenerateRequest) (*GenerateResponse, error)
	// CompileIR builds the relational IR (Schema) from the project's
	// proto set — the same stage→load→build prologue Generate runs
	// internally, stopping at the IR. Lets a thin client (w17ctl) build
	// IR over the API instead of embedding migrator/ir + migrator/loader.
	//
	// The client uploads its full file set (incl. plugin trees + the
	// domain's `w17.lock.acl.proto`) exactly as for Generate; the server
	// stages files, materializes plugin activations, loads via
	// protocompile, and builds the IR. ACL permission CHECK-lists are NOT
	// resolved server-side (the lock is a local artifact): the client
	// passes pre-resolved `acl_permissions` / `acl_permission_ids`, the
	// same union it computed locally before this RPC existed.
	//
	// INVALID_ARGUMENT for malformed/empty input or a build error;
	// INTERNAL for unexpected staging failures.
	CompileIR(context.Context, *CompileIRRequest) (*CompileIRResponse, error)
	// GenerateCi renders the opt-in CI configs for the requested providers
	// from the project's lock data (providers + connection names) — the
	// first of the seam-D generator family moved off w17ctl's in-process
	// migrator/cmd/cli onto a sibling codegen RPC (thin-client refactor
	// Step 3a). Returns the rendered files (relative paths + contents); the
	// client writes them under the project's CI tree (executable bit by
	// .sh suffix). CI generation needs no proto set — it's pure lock-driven
	// templating.
	GenerateCi(context.Context, *GenerateCiRequest) (*GenerateCiResponse, error)
	// GenerateEventbus renders the per-domain subscriber bundle(s) + the
	// events lock from the project's proto set (seam-D generator family,
	// thin-client refactor Step 3a). Distinct from the emit-interceptor
	// code Generate folds into the storage bundle: this is the standalone
	// `<domain>-eventbus/` module (main.go, dispatch, channels, Dockerfile,
	// …). The server stages the uploaded protos and runs the same
	// generator the CLI did; the client writes the returned files under its
	// services dir.
	GenerateEventbus(context.Context, *GenerateEventbusRequest) (*GeneratedFiles, error)
	// GenerateGrpcClients renders the typed gRPC client package(s) from the
	// project's services (seam-D, thin-client refactor Step 3a). Proto-only
	// (no generated-Go-tree read). Drives both the per-domain project-pb
	// clients and the w17/stubs partitioned clients (the request's `out` +
	// `w17_stubs_pb` select which). The server runs the same generator the
	// CLI did against the staged protos; the client writes the result under
	// `out`.
	GenerateGrpcClients(context.Context, *GenerateGrpcClientsRequest) (*GeneratedFiles, error)
	// GenerateMcp renders the per-domain MCP-server bundle(s) from the
	// project's MCP surface (seam-D, thin-client refactor Step 3a).
	// Proto-only. The client passes the bundle's replace-path knobs
	// (srcgo_rel / sdk_go_rel) it computes locally; the server runs the
	// generator and returns the bundle files.
	GenerateMcp(context.Context, *GenerateMcpRequest) (*GeneratedFiles, error)
	// GenerateAcl refreshes the per-domain ACL permission lock
	// (`w17.lock.acl.proto`) from the project's `(w17.acl)` surface (seam-D,
	// thin-client refactor Step 3a). Proto-only, no knobs — the generator
	// resolves the w17 vocab from the server's own proto root. Returns the
	// regenerated lock(s); the client writes them back into the proto tree.
	GenerateAcl(context.Context, *GenerateAclRequest) (*GeneratedFiles, error)
	// GenerateBusiness renders the generated <domain>-business bundle(s)
	// (the binary w17 builds for a domain when the project opts in via the
	// lock's business_bundles) (seam-D, thin-client refactor Step 3a).
	// Proto-only apart from reading the project's gen-dir go.mod for the
	// grpc version, which the client uploads in `go_mod`.
	GenerateBusiness(context.Context, *GenerateBusinessRequest) (*GeneratedFiles, error)
	// GenerateProjectMap renders the AI navigation map (w17/map/*.map +
	// w17/AGENTS.md) from the project's proto surface (seam-D, thin-client
	// refactor Step 3a). Best-effort. The grpc-client cross-domain edges are
	// derived from the generated Go tree, which the client uploads in
	// `gen_files` (empty = proto-only map, those edges omitted).
	GenerateProjectMap(context.Context, *GenerateProjectMapRequest) (*GeneratedFiles, error)
	// GenerateE2e scaffolds the generated e2e test skeletons (one
	// gRPC-shaped test per REST/MCP endpoint, generate-if-missing) from the
	// project's surface (seam-D, thin-client refactor Step 3a). Proto-only.
	GenerateE2E(context.Context, *GenerateE2ERequest) (*GeneratedFiles, error)
	// GenerateProject runs the WHOLE codegen pipeline server-side and streams
	// the resulting filesystem operations. It absorbs the orchestration that
	// used to live in the client (`internal/codegen.Run` +
	// `runDeclaredGenerators`): surface detection, target derivation,
	// composition, and the per-generator sequencing — calling every other
	// Generate* method internally. The thin client only gathers LOCAL inputs
	// (the proto tree, the lock, the go.mod dep-versions, the co-dev env), and
	// applies each streamed op under the project root. WRITE ops carry a file;
	// DELETE ops carry a path the server determined is superseded (the
	// bundle-sweep / clean-paths logic moved server-side too), so the client
	// does no derivation — just overwrite / write-if-missing / remove.
	GenerateProject(*GenerateProjectRequest, grpc.ServerStreamingServer[GeneratedOp]) error
	// VerifyAcl / VerifyEventbus recompute the committed lock from the
	// uploaded proto set (which includes the committed lock) and report
	// whether it still matches — the CI drift hook (`w17ctl verify`),
	// thin-client refactor Step 3a. Drift is reported as `ok=false` +
	// a message, NOT a gRPC error (it's an expected outcome).
	VerifyAcl(context.Context, *VerifyRequest) (*VerifyResult, error)
	VerifyEventbus(context.Context, *VerifyRequest) (*VerifyResult, error)
	// VerifyLock checks the committed `w17/lock.yaml` signature server-side
	// — the client performs ZERO cryptography (public-split boundary §4: no
	// signing key in the public binary). The thin client ships the on-disk
	// lock bytes; the console (which holds the verifier) confirms the
	// signature + canonical form. The CI consistency hook (`w17ctl verify`):
	// a hand-edited / tampered / unsigned committed lock is reported as
	// `ok=false` + a message, NOT a gRPC error (an expected outcome).
	VerifyLock(context.Context, *VerifyLockRequest) (*VerifyResult, error)
	// Classify runs the compat engine (lib/compat — the DB/WIRE/API
	// breaking-change classifier) over two compiled IR states base→head and
	// returns the findings + the dev/prod gate decision (public-split: the
	// engine is a COMPILER concern, so the thin client classifies over the
	// API instead of holding lib/compat or the IR type). base/head are the
	// opaque marshalled IR bytes the client already carries (a snapshot's
	// `ir_schema` or a fresh CompileIR output) — like CompileIRResponse.schema,
	// so this PUBLIC contract pulls in no compiler-internal typed proto. An
	// empty base = initial state (everything in head is an addition).
	Classify(context.Context, *ClassifyIRRequest) (*ClassifyIRResponse, error)
	// Plan runs the migration planner (the engine.Plan diff engine — a
	// COMPILER concern) over two compiled IR states base→head and returns the
	// rendered per-connection migration plan. base/head are the opaque
	// marshalled IR bytes the client already carries (a checkpoint's ir_schema
	// or a fresh CompileIR output); the returned plan is itself opaque bytes
	// (a marshalled migrator plan) the thin client APPLIES to its local stores
	// — so this PUBLIC contract pulls in no compiler-internal typed proto.
	// Empty base = initial migration (full create); empty head = teardown.
	Plan(context.Context, *PlanIRRequest) (*PlanIRResponse, error)
	// GenerateClient renders the FE client tree(s) (TS/JS/React/Vue)
	// declared in the lock's generated_code.clients[] (seam-D, thin-client
	// refactor Step 3a — the last generator off the in-process toolchain).
	// The server runs the FE client generator against the staged proto set
	// + lock; the client writes the returned trees under each client's
	// output_root.
	GenerateClient(context.Context, *GenerateClientRequest) (*GeneratedFiles, error)
	// DiscoverPluginSandboxes returns each activated plugin's dev-only
	// sandbox declarations (image services the project's compose tree
	// wires in) — discovering activations needs the proto loader, so a
	// thin client asks the console instead of parsing locally (thin-client
	// refactor Step 3a). The client folds the result into its
	// (loader-free) compose render.
	DiscoverPluginSandboxes(context.Context, *DiscoverPluginSandboxesRequest) (*PluginSandboxes, error)
	// GeneratePluginPb compiles a plugin's standalone src/gen/pb from its
	// proto/ tree (the author-side `plugin gen-pb` dev/test loop). The
	// client uploads the raw plugin protos + plugin.yaml; the server parses
	// the manifest, expands the author-side placeholders, runs buf, and
	// returns the pb.go files. The client only reads the inputs + writes
	// the results — no buf/loader/manifest logic client-side.
	GeneratePluginPb(context.Context, *GeneratePluginPbRequest) (*GeneratedFiles, error)
	// MergePo merges the freshly-scaffolded .po catalog INTO the existing
	// on-disk one (msgmerge-style: existing translator msgstrs survive, new
	// scaffold msgids land with empty msgstr). The .po merge is i18n logic,
	// so it runs server-side; the client reads the existing file, ships
	// both, and writes the returned merged body.
	MergePo(context.Context, *MergePoRequest) (*MergePoResponse, error)
	// RenderProjectScaffold renders the project-level compose.w17.yaml
	// (tool-owned, always) + the once-only compose.yaml stub. The render is
	// composegen/managegen logic, so it runs server-side: the client ships
	// the lock + the on-disk bundle compose-include paths + the protos (for
	// plugin-sandbox discovery), and writes the returned files (compose.yaml
	// only when absent). Returns compose.w17.yaml + compose.yaml.
	RenderProjectScaffold(context.Context, *RenderProjectScaffoldRequest) (*GeneratedFiles, error)
	// EditLock applies one editor INTENT to the lock and returns the
	// re-signed bytes (public-split Block 2 §8.2). The console owns the
	// lock: a dumb client must not sign (boundary §4) and editing requires
	// re-signing, so editor commands ship the current lock bytes + a typed
	// intent rather than constructing lockpb themselves. The server decodes,
	// applies the intent, validates (dup names, default conflicts, …),
	// re-signs via lock/sealing, and returns canonical bytes the client
	// writes to w17/lock.yaml. Empty lock = a fresh project (the intent
	// bootstraps it). The oneof grows one arm per editor family.
	EditLock(context.Context, *EditLockRequest) (*EditLockResponse, error)
	// DescribeLock decodes the lock and returns the routing fields the thin
	// client reads (public-split Block 2 §8.2) — replacing client-side
	// lock.Effective* / lockpb parsing. The console address (w17_url) is NOT
	// here: you can't dial the console to learn where it is, so that one
	// field is sourced from flag / env / registry / compiled default instead.
	DescribeLock(context.Context, *DescribeLockRequest) (*LockView, error)
	// InspectPluginManifest parses + validates a plugin's plugin.yaml and runs
	// its requirement check server-side — the plugin-system semantics
	// (Manifest schema + Validate + CheckRequires) are compiler-domain, so the
	// thin client uploads the raw manifest bytes + the installed-plugin set and
	// gets back the identity (name/version) it records + any requirement
	// warnings to print. Replaces the client-side console/plugins ParseManifest
	// / CheckRequires (public-split Block 3). A parse / validation failure is a
	// gRPC INVALID_ARGUMENT — the client surfaces it as the install/update
	// refusal.
	InspectPluginManifest(context.Context, *InspectPluginManifestRequest) (*InspectPluginManifestResponse, error)
	// Guide renders the w17 PLATFORM self-description — the w17/specs/ reference
	// (annotation catalog + architecture primer + escape hatches) a coding agent
	// reads to understand the technology before designing a project. It is
	// generated SERVER-SIDE (the annotation catalog walks the compiler's own w17
	// proto option definitions) so an old thin client never ships an outdated
	// description: when codegen changes, the reference changes with it. Takes no
	// project input — the vocabulary is the compiler's. The files ride back on
	// the shared GeneratedFiles envelope (relative paths under the project's
	// w17/ tree), which the client writes verbatim.
	Guide(context.Context, *GuideRequest) (*GeneratedFiles, error)
	mustEmbedUnimplementedCodegenServiceServer()
}

